USE payroll_2026;

-- ============================================================
-- PHẦN 1: ĐỒNG BỘ 100 NHÂN VIÊN VÀO employees_payroll
-- ============================================================

-- ============================================================
-- PHẦN 2: BẢNG LƯƠNG 12 THÁNG (5/2025 → 4/2026)
-- Tổng ~1,100 bản ghi (trừ Inactive sau tháng 10/2025)
-- ============================================================


























-- ============================================================
-- PHẦN 3: CHẤM CÔNG 12 THÁNG (5/2025 → 4/2026)
-- ============================================================


























-- ============================================================
-- KIỂM TRA KẾT QUẢ
-- ============================================================

SELECT 'Tong nhan vien payroll' AS stat, COUNT(*) AS val FROM employees_payroll
UNION ALL
SELECT 'Tong ban ghi luong',           COUNT(*) FROM salaries
UNION ALL
SELECT 'Tong ban ghi cham cong',       COUNT(*) FROM attendance
UNION ALL
SELECT 'Luong am (anomaly)',           COUNT(*) FROM salaries WHERE (BaseSalary + Bonus - Deductions) < 0
UNION ALL
SELECT 'Vang nhieu > 5 ngay',         COUNT(*) FROM attendance WHERE AbsentDays > 5;
